// // This comment suggests that the multiplexer selects B when S is 0, which is the opposite of the actual behavior.
module mux_2_to_1 (
    output reg Y,
    input A,
    input B,
    input S
);

always @(*) begin
    if (S == 0) begin
        Y = A;
    end else begin
        Y = B;
    end
end

endmodule
